  const hasImageAttach = React.useMemo(() => {
    return (
      attachs?.attachType === AttachType.MultiAttachment &&
      (attachs as IMultiAttachment)?.dataSource?.some(
        (i) =>
          i.attachType === AttachType.ImageUrl &&
          (i as ImageUrl)?.imgUrls?.length > 0,
      )
    );
  }, [attachs]);

