  // 质量问题修复功能
  React.useEffect(() => {
    function handleMessage(event: MessageEvent) {
      if (event.data.type === SubscribeActions.CODEBASE_QUALITY_ISSUE_AUTOFIX) {
        const autofixData = event.data.data;
        if (
          isStreaming ||
          isProcessing ||
          isMCPProcessing ||
          isTerminalProcessing ||
          isApplying
        ) {
          toast({
            title: '当前对话正在处理中，请稍后再试',
            status: 'info',
            duration: 4000,
