              if (attachs?.attachType === AttachType.KnowledgeAugmentation) {
                updateAttach(undefined);
              } else {
                updateAttach({
                  attachType: AttachType.KnowledgeAugmentation,
                });
              }
            }}
          >
            <Icon as={GrBook} size="xxs" />
