import {
  Box,
  IconButton,
  Spinner,
  Tooltip,
  Tag,
  Button,
  useOutsideClick,
} from '@chakra-ui/react';
import { useCallback, useEffect, useMemo, useState, useRef } from 'react';
import { AiOutlineClear, AiOutlineSetting } from 'react-icons/ai';
import { TbChevronRight, TbChevronDown, TbLoader2, TbRefresh } from 'react-icons/tb';
import { GroupBase, Select } from 'chakra-react-select';
import Icon from '../../../components/Icon';
import useFirstFocusedEffect from '../../../hooks/useFirstFocusEffect';
import {
  BroadcastActions,
  SubscribeActions,
  usePostMessage,
} from '../../../PostMessageProvider';
import { IDE, useExtensionStore } from '../../../store/extension';
import {
  useLocalReviewStore,
  WorkspaceRepoInfo
} from '../../../store/localReview';
import ClearLocalReviewHistoryModal from './ClearLocalReviewHistoryModal';
import LocalReviewSettingModal from './LocalReviewSettingModal';
import LocalReviewTask from './LocalReviewTask';
import FileSelectionModal from './FileSelectionModal';
import ReviewCommitModal from './ReviewCommitModal';
import { DEV_CLOUD_UI } from '../../CodeCoverage/const';
import { RemoteConfig } from '../../../services/localReview';
import {
  formatRepoUrl,
  getRepoGroupPrefix,
} from '../../CodeReview/utils';
import { useTheme } from '../../../ThemeContext';
import { shallow } from 'zustand/shallow';

/**
 * 仓库选项（分组内的单个选项）
 */
interface RepoOption {
  label: string; // 显示的路径（去掉分组前缀）
  value: WorkspaceRepoInfo; // 原始仓库数据
  fullUrl: string; // 完整 URL（用于选中时显示和搜索）
}

/**
 * 仓库分组
 */
interface RepoGroup {
  label: string; // 分组标题（域名/路径前缀）
  options: RepoOption[]; // 分组内的仓库选项
}


function LocalReview() {
  const { postMessage } = usePostMessage();
  const { activeTheme } = useTheme();

  const {
    initStore,
    startCodeReview,
    startCommitReview,
    setSubmitLoading,
    loading,
    submitLoading,
    reviewList,
    clearHistoryLoading,
    loadMoreReviewList,
    hasMore,
    scrollLoading,
    remoteConfig,
    workspaceRepoList,
    switchRepo,
    isFileSelectionModalOpen,
    setFileSelectionModalOpen,
    refreshReviewList,
    setLoading,
    isCommitReviewModalOpen,
    setCommitReviewModalOpen,
    setCommitsList,
    appendCommitsList,
    setCommitReviewContext,
  } = useLocalReviewStore((state) => ({
    initStore: state.initStore,
    startCodeReview: state.startCodeReview,
    startCommitReview: state.startCommitReview,
    setSubmitLoading: state.setSubmitLoading,
    loading: state.loading,
    submitLoading: state.submitLoading,
    reviewList: state.reviewList,
    clearHistoryLoading: state.clearHistoryLoading,
    loadMoreReviewList: state.loadMoreReviewList,
    hasMore: state.hasMore,
    scrollLoading: state.scrollLoading,
    remoteConfig: state.remoteConfig,
    workspaceRepoList: state.workspaceRepoList,
    switchRepo: state.switchRepo,
    isFileSelectionModalOpen: state.isFileSelectionModalOpen,
    setFileSelectionModalOpen: state.setFileSelectionModalOpen,
    refreshReviewList: state.refreshReviewList,
    setLoading: state.setLoading,
    isCommitReviewModalOpen: state.isCommitReviewModalOpen,
    setCommitReviewModalOpen: state.setCommitReviewModalOpen,
    setCommitsList: state.setCommitsList,
    appendCommitsList: state.appendCommitsList,
    setCommitReviewContext: state.setCommitReviewContext,
  }), shallow);

  const repoAddress = useLocalReviewStore((state) => state.address);
  const workspaceRepo = useLocalReviewStore((state) => state.workspaceRepo);
  const originalWorkspaceRepo = useLocalReviewStore((state) => state.originalWorkspaceRepo);

  const [isOpenClearModal, setIsOpenClearModal] = useState(false);
  const [isOpenSettingModal, setIsOpenSettingModal] = useState(false);
  const [isRepoSelectOpen, setIsRepoSelectOpen] = useState(false);
  const [selectedRepo, setSelectedRepo] = useState<WorkspaceRepoInfo | null>(
    null,
  );
  const selectRef = useRef<any>(null);
  const [quickSelectPosition, setQuickSelectPosition] = useState<{
    x: number;
    y: number;
  }>({ x: 0, y: 0 });
  const quickSelectRef = useRef<HTMLDivElement>(null);
  const portalRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const ide = useExtensionStore((state) => state.IDE);
  const supportCommitReview = useMemo(() => {
    return ide !== IDE.VisualStudio;
  }, [ide]);

  // 获取仓库显示标签的通用函数
  const getRepoDisplayLabel = useCallback(
    (repo: WorkspaceRepoInfo) => {
      // 如果 localRepoType 是 noRepo，说明是非仓库（根目录）
      if (repo.localRepoType === 'noRepo') {
        return '根目录（非仓库）';
      }

      // 如果没有 localRepoUrl，说明是本地仓库但URL未配置
      if (!repo.localRepoUrl) {
        return `[本地仓库] ${repo.localRepoName}`;
      }

      // 有 URL 的仓库，直接返回完整 URL
      return formatRepoUrl(repo.localRepoUrl, repo.localRepoType ?? '');
    },
    [],
  );

  /**
   * 将仓库列表按域名/路径前缀分组
   */
  const groupReposByPrefix = useCallback(
    (repos: WorkspaceRepoInfo[]): RepoGroup[] => {
      const grouped = new Map<string, RepoOption[]>();
      const localRepos: RepoOption[] = []; // 存储本地仓库
      const noRepos: RepoOption[] = []; // 存储非仓库（noRepo）

      repos.forEach((repo) => {
        // 处理无 URL 的情况
        if (!repo.localRepoUrl) {
          const label = getRepoDisplayLabel(repo);
          const option: RepoOption = {
            label: label,
            value: repo,
            fullUrl: '',
          };

          // 根据 localRepoType 分类
          if (repo.localRepoType === 'noRepo') {
            noRepos.push(option);
          } else {
            localRepos.push(option);
          }
          return;
        }

        const fullUrl = formatRepoUrl(
          repo.localRepoUrl,
          repo.localRepoType ?? '',
        );
        const groupPrefix = getRepoGroupPrefix(fullUrl);

        // 计算显示 label（去掉分组前缀）
        let displayLabel = fullUrl.replace(groupPrefix, '');
        // 如果去掉前缀后为空或只剩斜杠，显示根路径标识
        if (!displayLabel || displayLabel === '/') {
          displayLabel = '/';
        }

        if (!grouped.has(groupPrefix)) {
          grouped.set(groupPrefix, []);
        }

        grouped.get(groupPrefix)!.push({
          label: displayLabel,
          value: repo,
          fullUrl: fullUrl,
        });
      });

      // 转换为数组格式，并按分组前缀排序
      const groups = Array.from(grouped.entries())
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([prefix, options]) => ({
          label: prefix,
          options: options,
        }));

      // 将本地仓库和非仓库添加到最前面
      if (localRepos.length > 0) {
        groups.unshift({
          label: '本地仓库',
          options: localRepos,
        });
      }
      if (noRepos.length > 0) {
        groups.unshift({
          label: '非仓库目录',
          options: noRepos,
        });
      }

      return groups;
    },
    [getRepoDisplayLabel],
  );

  // 缓存分组结果
  const repoGroups = useMemo(() => {
    if (!originalWorkspaceRepo) {
      return groupReposByPrefix(workspaceRepoList);
    }

    // 检查根目录是否已经在 workspaceRepoList 中
    const isDuplicate = workspaceRepoList.some(
      (repo) =>
        repo.localRepoName === originalWorkspaceRepo.localRepoName &&
        repo.localRepoUrl === originalWorkspaceRepo.localRepoUrl,
    );

    // 如果根目录已存在于列表中，不重复添加
    const allRepos = isDuplicate
      ? workspaceRepoList
      : [originalWorkspaceRepo, ...workspaceRepoList];

    return groupReposByPrefix(allRepos);
  }, [workspaceRepoList, originalWorkspaceRepo, groupReposByPrefix]);

  useEffect(() => {
    if (isRepoSelectOpen && selectRef.current) {
      setTimeout(() => {
        selectRef.current?.focus();
      }, 0);
    }
  }, [isRepoSelectOpen]);

  const handleRepoConfirm = useCallback(() => {
    if (selectedRepo) {
      switchRepo(selectedRepo);
      setSelectedRepo(null);
    }
    setIsRepoSelectOpen(false);
  }, [selectedRepo, switchRepo]);

  // 处理点击外部关闭
  useOutsideClick({
    ref: quickSelectRef,
    handler: (e: Event) => {
      if (!isRepoSelectOpen) return;

      // 如果点击的是 portal 内的元素（Select 下拉菜单），不关闭
      if (portalRef.current?.contains(e.target as Node)) {
        return;
      }

      // 如果点击的是 Select 下拉菜单相关元素，不关闭
      const target = e.target as HTMLElement;
      if (
        target.closest('[class*="menu"]') ||
        target.closest('[class*="option"]')
      ) {
        return;
      }

      setIsRepoSelectOpen(false);
      setSelectedRepo(null);
    },
  });

  // 处理标签点击，显示快捷选择器
  const handleRepoTagClick = useCallback((event: React.MouseEvent) => {
    event.stopPropagation();
    const rect = event.currentTarget.getBoundingClientRect();
    setQuickSelectPosition({
      x: rect.left,
      y: rect.bottom + 4,
    });
    setIsRepoSelectOpen(true);
  }, []);

  useFirstFocusedEffect(() => {
    postMessage({
      type: supportCommitReview
        ? BroadcastActions.GET_LOCAL_REVIEW_CONFIG
        : BroadcastActions.GET_LOCAL_REVIEW_CONFIG_OLD,
    });
  }, [postMessage, supportCommitReview]);

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      const { type, data } = event.data || {};
      switch (type) {
        case SubscribeActions.START_CODE_REVIEW: {
          startCodeReview(data).then(() => {
            setTimeout(() => {
              scrollToBottom();
            }, 100);
          });
          break;
        }
        case SubscribeActions.START_COMMIT_REVIEW: {
          startCommitReview(data).then(() => {
            setTimeout(() => {
              scrollToBottom();
            }, 100);
          });
          break;
        }
        case SubscribeActions.OPEN_LOCAL_REVIEW_SETTING: {
          setIsOpenSettingModal(true);
          break;
        }
        case SubscribeActions.LOCAL_REVIEW_CONFIG:
        case SubscribeActions.LOCAL_REVIEW_CONFIG_OLD:
          // import('./localReviewConfig.test.ts').then(({ testScenariosArray }) => {
          //   const testScenario = testScenariosArray[0]; // 修改索引切换场景 (0-10)
          //   initStore(testScenario as any);
          // })
          initStore(data).then(() => {
            setTimeout(() => {
              scrollToBottom();
            }, 100);
          });
          break;
        case SubscribeActions.LOCAL_REVIEW_LOADING_START: {
          setSubmitLoading(true);
          break;
        }
        case SubscribeActions.LOCAL_REVIEW_LOADING_FINISH: {
          setSubmitLoading(false);
          break;
        }
        case SubscribeActions.LOCAL_COMMITS_LIST: {
          const { commits, hasMore, page, workspaceRepo: wsRepo, scmRootUri } = data || {};
          if (page === 1) {
            setCommitsList(commits || [], hasMore, page);
            if (scmRootUri || wsRepo) {
              setCommitReviewContext(scmRootUri || '', wsRepo || null);
            }
          } else {
            appendCommitsList(commits || [], hasMore, page);
          }
          break;
        }
        case SubscribeActions.OPEN_COMMIT_REVIEW_MODAL: {
          setCommitReviewModalOpen(true);
          break;
        }
        default: {
          break;
        }
      }
    };
    window.addEventListener('message', handleMessage);
    return () => {
      window.removeEventListener('message', handleMessage);
    };
  }, [
    postMessage,
    supportCommitReview,
    startCodeReview,
    startCommitReview,
    initStore,
    setCommitsList,
    appendCommitsList,
    setCommitReviewContext,
    setCommitReviewModalOpen,
    setSubmitLoading,
  ]);

  const handleOpenLocalFile = useCallback(
    (filePath: string, lineNumber: number) => {
      if (supportCommitReview) {
        postMessage({
          type: BroadcastActions.OPEN_LOCAL_REVIEW_FILE,
          data: {
            filePath,
            lineNumber: lineNumber - 1,
          },
        });
      } else {
        postMessage({
          type: BroadcastActions.OPEN_LOCAL_REVIEW_FILE_OLD,
          data: filePath,
        });
      }
    },
    [supportCommitReview, postMessage],
  );

  const handleScroll = useCallback(
    (e: React.UIEvent<HTMLDivElement>) => {
      const { scrollTop } = e.currentTarget;
      if (scrollLoading || !hasMore) return;
      if (scrollTop <= 20) {
        // 加载完成后，调整 scrollTop 保持位置
        const prevScrollHeight = scrollContainerRef.current?.scrollHeight || 0;
        loadMoreReviewList().then(() => {
          if (scrollContainerRef.current) {
            const newScrollHeight = scrollContainerRef.current.scrollHeight;
            scrollContainerRef.current.scrollTop = newScrollHeight - prevScrollHeight;
          }
        });
      }
    },
    [loadMoreReviewList, scrollLoading, hasMore],
  );

  // 滚动到底部
  const scrollToBottom = useCallback(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, []);

  // 处理刷新按钮点击
  const handleRefresh = useCallback(async () => {
    try {
      setLoading(true);
      await refreshReviewList();
      setTimeout(() => {
        scrollToBottom();
      }, 100);
    } catch (error) {
      console.error('刷新失败:', error);
    } finally {
      setLoading(false);
    }
  }, [refreshReviewList, scrollToBottom, setLoading]);

  const renderReviewList = useCallback(() => {
    if (loading) {
      return <div className="mt-2">数据加载中，请稍等...</div>;
    }

    if (!reviewList.length) {
      return (
        <div className="mt-2">
          {supportCommitReview
            ? 'Local Review 支持对本地暂存区代码或指定文件一键发起 AI Review，并返回 Review 结果，快来体验吧～'
            : 'Local Review 支持对指定文件一键发起 AI Review，并返回 Review 结果，快来体验吧～'}
        </div>
      );
    }

    return (
      <div
        className="pt-2 h-full"
        style={{ paddingBottom: supportCommitReview ? 180 : 80 }}
      >
        <div
          ref={scrollContainerRef}
          className="h-full overflow-y-auto"
          onScroll={handleScroll}
          style={{ maxHeight: 'calc(100vh - 190px)' }}
        >
          <Box
            className="mt-4 mb-4"
            display="flex"
            justifyContent="center"
            fontSize="12px"
            color="text.default"
          >
            {scrollLoading ? <Spinner size="sm" /> : null}
            {!hasMore && reviewList.length > 0 ? (
              <span>没有更多数据了</span>
            ) : null}
          </Box>
          <div className="flex flex-col gap-4">
            {reviewList?.map((data, index) => (
              <LocalReviewTask
                key={data.task_id}
                index={index}
                data={data}
                onClickIssue={handleOpenLocalFile}
              />
            ))}
          </div>
        </div>
      </div>
    );
  }, [
    loading,
    reviewList,
    handleOpenLocalFile,
    supportCommitReview,
    scrollLoading,
    hasMore,
    handleScroll,
  ]);

  const renderBottomActions = useCallback(() => {
    if (supportCommitReview) {
      return (
        <div className="fixed bottom-0 left-4 right-4">
          <button
            className={`flex items-center p-4 text-left w-full rounded-t-xl ${submitLoading ? activeTheme === 'light' ? '!bg-gray-50 !bg-opacity-80 text-[#786fff] cursor-not-allowed' : '!bg-gray-100 !bg-opacity-20 text-[#786fff] cursor-not-allowed' : 'hover:bg-opacity-80 hover:text-[#786fff]'}`}
            disabled={submitLoading}
            style={{
              backgroundColor: 'var(--chakra-colors-panelBgColor)',
            }}
            onClick={() => {
              console.log({
                type: BroadcastActions.START_LOCAL_REVIEW,
                data: {
                  path: workspaceRepo?.path,
                  localRepoUrl: workspaceRepo?.localRepoUrl,
                },
              });
              postMessage({
                type: BroadcastActions.START_LOCAL_REVIEW,
                data: {
                  path: workspaceRepo?.path,
                  localRepoUrl: workspaceRepo?.localRepoUrl,
                },
              });
            }}
          >
            <div className="flex-1">
              <div className="font-bold mb-1">Review 本地待提交代码</div>
              <div className="text-sm opacity-50">
                对本地暂存区代码一键发起 AI Review，发现潜在问题
              </div>
            </div>
            {submitLoading ? <TbLoader2 className="animate-spin" /> : <TbChevronRight className="text-xl" />}
          </button>
          <div
            className="px-4"
            style={{
              backgroundColor: 'var(--chakra-colors-panelBgColor)',
            }}
          >
            <div className="w-full h-[1px] bg-[#d7d7d7] opacity-50"></div>
          </div>
          <div
            className="p-4 cursor-default"
            style={{
              backgroundColor: 'var(--chakra-colors-panelBgColor)',
            }}
          >
            <div className="font-bold mb-1">Review 指定文件代码</div>
            <div className="text-sm">
              请在文件内选中代码，右键选择 CodeMaker 发起 Review
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="fixed bottom-0 left-4 right-4">
        <div
          className="p-4 cursor-default rounded-t-xl"
          style={{
            backgroundColor: 'var(--chakra-colors-panelBgColor)',
          }}
        >
          <div className="font-bold mb-1">Review 指定文件代码</div>
          <div className="text-sm">
            请在文件内选中代码，右键选择 CodeMaker 发起 Review
          </div>
        </div>
      </div>
    );
  }, [supportCommitReview, postMessage, workspaceRepo, submitLoading]);

  return (
    <div className="h-full">
      <Box
        ref={portalRef}
        position="fixed"
        top={0}
        left={0}
        right={0}
        bottom={0}
        pointerEvents="none"
        zIndex={9999}
      />

      <div className="absolute w-full -top-9 left-0 flex justify-end gap-1">
        <Tooltip label="刷新">
          <IconButton
            aria-label="刷新"
            size="xs"
            icon={<Icon as={TbRefresh} size="sm" />}
            onClick={handleRefresh}
            bg="none"
            color="text.default"
            isLoading={loading}
          />
        </Tooltip>
        {reviewList.length > 0 && (
          <Tooltip label="清空内容">
            <IconButton
              aria-label="清空内容"
              size="xs"
              icon={<Icon as={AiOutlineClear} size="sm" />}
              onClick={() => {
                setIsOpenClearModal(true);
              }}
              bg="none"
              color="text.default"
            />
          </Tooltip>
        )}
      </div>

      <div className="flex items-center gap-2">
        {workspaceRepoList.length > 1 ? (
          <>
            <Tooltip
              label={
                workspaceRepo
                  ? getRepoDisplayLabel(workspaceRepo)
                  : '根目录（非仓库）'
              }
            >
              <Tag
                className="cursor-pointer hover:text-[#786fff] hover:bg-[#786fff]/20 transition flex items-center min-w-0"
                onClick={handleRepoTagClick}
                style={{ maxWidth: '400px' }}
              >
                <span className="mr-1 flex-shrink-0">仓库:</span>
                {workspaceRepo && workspaceRepo.localRepoUrl ? (
                  (() => {
                    const fullUrl = formatRepoUrl(
                      workspaceRepo.localRepoUrl,
                      workspaceRepo.localRepoType ?? '',
                    );
                    const halfLen = Math.floor(fullUrl.length / 2);
                    const textLeft = fullUrl.slice(0, halfLen);
                    const textRight = fullUrl.slice(halfLen);
                    return (
                      <div
                        className="flex items-center min-w-0 flex-1"
                        title={fullUrl}
                      >
                        <span className="truncate" style={{ flex: '0 1 auto' }}>
                          {textLeft}
                        </span>
                        <span
                          className="truncate"
                          style={{
                            flex: '0 1 auto',
                            textOverflow: 'clip',
                            direction: 'rtl',
                            textAlign: 'left',
                          }}
                        >
                          &lrm;{textRight}&lrm;
                        </span>
                      </div>
                    );
                  })()
                ) : (
                  <span className="max-w-[200px] truncate">
                    {workspaceRepo
                      ? getRepoDisplayLabel(workspaceRepo)
                      : '根目录（非仓库）'}
                  </span>
                )}
                <TbChevronDown className="ml-1 flex-shrink-0" />
              </Tag>
            </Tooltip>
          </>
        ) : repoAddress ? (
          <Tooltip label={repoAddress}>
            <div
              className="w-fit px-2 py-[2px] rounded text-sm text-nowrap truncate"
              style={{
                backgroundColor: 'var(--chakra-colors-panelBgColor)',
              }}
            >
              当前仓库：{repoAddress}
            </div>
          </Tooltip>
        ) : (
          <Tooltip label="根目录（非仓库）">
            <div
              className="w-fit px-2 py-[2px] rounded text-sm text-nowrap truncate"
              style={{
                backgroundColor: 'var(--chakra-colors-panelBgColor)',
              }}
            >
              当前目录：根目录（非仓库）
            </div>
          </Tooltip>
        )}
        {remoteConfig && (
          <Tooltip
            label={
              <div className="whitespace-pre-wrap">
                {getRemoteConfigTooltip(remoteConfig)}
              </div>
            }
          >
            <div
              className="px-2 py-[2px] rounded text-sm text-nowrap bg-[var(--chakra-colors-panelBgColor)] hover:text-[#786fff] hover:bg-[#786fff]/20 cursor-pointer"
              onClick={() => {
                postMessage({
                  type: BroadcastActions.OPEN_IN_BROWSER,
                  data: {
                    url: `${DEV_CLOUD_UI}/_${remoteConfig.project}/code_quality/code_review?tab=review-config&repo=${encodeURIComponent(remoteConfig.address)}`,
                  },
                });
              }}
            >
              已接入
            </div>
          </Tooltip>
        )}
        {repoAddress && (
          <Tooltip label="设置发起 Local Review 需要仅包含或排除的目录">
            <IconButton
              aria-label="设置"
              size="xs"
              icon={<Icon as={AiOutlineSetting} size="sm" />}
              onClick={() => {
                setIsOpenSettingModal(true);
              }}
              bg="none"
              color="text.default"
            />
          </Tooltip>
        )}
      </div>

      {renderReviewList()}
      {renderBottomActions()}

      <ClearLocalReviewHistoryModal
        isOpen={isOpenClearModal}
        onClose={() => setIsOpenClearModal(false)}
      />

      <LocalReviewSettingModal
        isOpen={isOpenSettingModal}
        onClose={() => setIsOpenSettingModal(false)}
      />

      <FileSelectionModal
        isOpen={isFileSelectionModalOpen}
        onClose={() => setFileSelectionModalOpen(false)}
      />

      <ReviewCommitModal
        isOpen={isCommitReviewModalOpen}
        onClose={() => setCommitReviewModalOpen(false)}
      />

      {clearHistoryLoading && (
        <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center text-[#786FFF]">
          <Spinner size="sm" />
          <span className="ml-1">正在清空历史记录...</span>
        </div>
      )}

      {/* 仓库快捷选择组件 */}
      {isRepoSelectOpen && workspaceRepoList.length > 1 && (
        <Box
          ref={quickSelectRef}
          position="fixed"
          className="rounded z-[1000] w-full min-w-[300px] text-left px-3 py-4"
          style={{
            left: `${quickSelectPosition.x}px`,
            top: `${quickSelectPosition.y}px`,
            maxWidth: 'min(500px, 80vw)',
            border: '1px solid rgba(255, 255, 255, 0.16)',
            boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
            background: 'var(--chakra-colors-themeBgColor)',
          }}
          onClick={(e) => e.stopPropagation()}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              handleRepoConfirm();
            }
          }}
        >
          <Box className="flex items-center gap-2">
            <Box flex={1}>
              <Select<RepoOption, false, GroupBase<RepoOption>>
                ref={selectRef}
                inputId="repo-select"
                size="sm"
                placeholder="请选择仓库"
                options={repoGroups}
                value={(() => {
                  const currentRepo = selectedRepo || workspaceRepo;
                  if (!currentRepo) return undefined;

                  // 处理无 URL 的仓库
                  if (!currentRepo.localRepoUrl) {
                    return {
                      label: getRepoDisplayLabel(currentRepo),
                      value: currentRepo,
                      fullUrl: '',
                    };
                  }

                  const fullUrl = formatRepoUrl(
                    currentRepo.localRepoUrl,
                    currentRepo.localRepoType ?? '',
                  );
                  const groupPrefix = getRepoGroupPrefix(fullUrl);
                  let displayLabel = fullUrl.replace(groupPrefix, '');
                  if (!displayLabel || displayLabel === '/') {
                    displayLabel = '/';
                  }

                  return {
                    label: displayLabel,
                    value: currentRepo,
                    fullUrl: fullUrl,
                  };
                })()}
                onChange={(option) => {
                  if (option?.value) {
                    setSelectedRepo(option.value);
                  }
                }}
                menuPortalTarget={portalRef.current || document.body}
                styles={{
                  menuPortal: (base) => ({
                    ...base,
                    zIndex: 1500,
                    pointerEvents: 'auto',
                  }),
                }}
                chakraStyles={{
                  dropdownIndicator: (provided) => ({
                    ...provided,
                    background: 'transparent',
                    padding: '0 4px 0 0',
                    cursor: 'pointer',
                    fontSize: 18,
                  }),
                  control: (provided) => ({
                    ...provided,
                    minHeight: '32px',
                  }),
                }}
                components={{ IndicatorSeparator: () => null }}
                autoFocus
                onFocus={(e) => {
                  e.stopPropagation();
                }}
                openMenuOnFocus
                formatGroupLabel={(group) => {
                  const label = group.label || '';
                  const halfLen = Math.floor(label.length / 2);
                  const textLeft = label.slice(0, halfLen);
                  const textRight = label.slice(halfLen);
                  return (
                    <Tooltip
                      label={label}
                      placement="top"
                      hasArrow
                      portalProps={{ containerRef: portalRef }}
                      zIndex={9999}
                    >
                      <div className="text-xs text-gray-400 font-semibold py-1 flex items-center min-w-0 break-all">
                        <span className="truncate" style={{ flex: '0 1 auto' }}>
                          {textLeft}
                        </span>
                        <span
                          className="truncate"
                          style={{
                            flex: '0 1 auto',
                            textOverflow: 'clip',
                            direction: 'rtl',
                            textAlign: 'left',
                          }}
                        >
                          &lrm;{textRight}&lrm;
                        </span>
                      </div>
                    </Tooltip>
                  );
                }}
                formatOptionLabel={(item: RepoOption, { context }) => {
                  const isMenu = context === 'menu';

                  // 处理无 URL 的仓库
                  if (!item.fullUrl) {
                    return (
                      <Tooltip
                        label={item.label}
                        placement="top"
                        hasArrow
                        portalProps={{ containerRef: portalRef }}
                        zIndex={9999}
                      >
                        <div className={`flex items-center min-w-0 w-full ${isMenu ? 'pl-4' : 'pl-0'}`}>
                          <span className="truncate">{item.label}</span>
                        </div>
                      </Tooltip>
                    );
                  }

                  // 处理有 URL 的仓库：对路径进行中间省略分割，不需要前缀
                  const halfLen = Math.floor(item.label.length / 2);
                  const textLeft = item.label.slice(0, halfLen);
                  const textRight = item.label.slice(halfLen);

                  return (
                    <Tooltip
                      label={item.fullUrl}
                      placement="top"
                      hasArrow
                      portalProps={{ containerRef: portalRef }}
                      zIndex={9999}
                    >
                      <div className={`flex items-center min-w-0 w-full break-all ${isMenu ? 'pl-4' : 'pl-0'}`}>
                        <span className="truncate" style={{ flex: '0 1 auto' }}>
                          {textLeft}
                        </span>
                        <span
                          className="truncate"
                          style={{
                            flex: '0 1 auto',
                            textOverflow: 'clip',
                            direction: 'rtl',
                            textAlign: 'left',
                          }}
                        >
                          &lrm;{textRight}&lrm;
                        </span>
                      </div>
                    </Tooltip>
                  );
                }}
                filterOption={(option, inputValue) => {
                  if (!inputValue) return true;
                  const searchStr = inputValue.toLowerCase();
                  // 搜索完整 URL 和显示 label
                  const fullUrl =
                    (option.data as RepoOption).fullUrl?.toLowerCase() || '';
                  const label = option.label?.toLowerCase() || '';
                  return (
                    fullUrl.includes(searchStr) || label.includes(searchStr)
                  );
                }}
              />
            </Box>
            <Button
              color="blue.300"
              variant="outline"
              size="sm"
              onClick={handleRepoConfirm}
            >
              确认
            </Button>
          </Box>
        </Box>
      )}
    </div>
  );
}

