const getRemoteConfigTooltip = (remoteConfig: RemoteConfig) => {
  const { include_path_pattern = [], exclude_path_pattern = [] } =
    remoteConfig || {};

  const includePaths = include_path_pattern.length
    ? include_path_pattern
    : ['--'];

  const excludePaths = exclude_path_pattern.length
    ? exclude_path_pattern
    : ['--'];

  return [
    '当前仓库已在远端接入，系统将默认读取远端配置的 include path、exclude path 和 AI 配置信息，若您希望优先使用本地配置，可点击右侧的设置按钮配置。注意：本地仅提供 exclude path、include path 配置。',
    '',
    '远端include path配置：',
    ...includePaths,
    '',
    '远端exclude path配置：',
    ...excludePaths,
    '',
    '点击该标签跳转远端查看配置',
  ].join('\n');
};

