  const [loadingRepo, setLoadingRepo] = React.useState(false);
  const [repoList, setRepoList] = React.useState<string[]>([]);
  const [repo, setRepo] = React.useState<GroupValue | undefined>();
  const { workspaceRepoRef } = useWorkspaceRepo();

  const portalRef = React.useRef<HTMLDivElement>(null);

  // 暴露方法到 ref 上，用来给上层调用 reviewRequest 列表获取
  React.useImperativeHandle(eRef, () => ({
    init: async () => {
      setLoadingRepo(true);
      proxyRequest(
        {
          method: 'get',
          requestUrl: `${TEAM_REVIEW_API_URL}/review_requests/personal_access_repo_paths`,
        },
        2 * 60 * 1000,
      )
        .then((res) => {
          const repoList = getUniqueRepo(res as Record<string, string[]>, true);
          setRepoList(repoList);
          updateRepoPathsCache(res as Record<string, string[]>);
        })
        .catch(() => [])
        .finally(() => {
          setLoadingRepo(false);
        });

      await new Promise((resolve) => setTimeout(resolve, 1000));
      const target = getRepoAddress(workspaceRepoRef.current);
      setRepo({ label: target, value: target });

      setTimeout(() => {
        onConfirm();
      }, 0);
    },
    search: (quiet = false) => {
      backupFilter();
      handleUpdateTag();
      const trimTitle = title?.trim();
      onSearch(
        {
          view: view?.value,
          repo: repo?.value,
          status: status?.value !== 'all' ? status?.value : '',
          reviewers: _.map(reviewers, (item) => item.value),
          authors: _.map(authors, (item) => item.value),
          labels: _.map(labels, (item) =>
            item.value === NO_LABEL_TITLE ? 'null' : item.value,
          ),
          title: trimTitle ? `%${trimTitle}%` : '',
          sequenceId,
          branch,
        },
        quiet,
      );
    },
  }));

  // clickoutside 时关掉弹窗
  useOutsideClick({
    ref: ref,
    handler: (e: Event) => {
      // 如果点击的是 portal 容器内的元素,不触发关闭
      if (quickFilterVisible) return;
      if (portalRef.current?.contains(e.target as Node)) {
        return;
      }
      onCancel();
    },
  });

  React.useEffect(() => {
    setFilterSequenceId(sequenceId);
  }, [sequenceId]);

  const { postMessage } = usePostMessage();
  useFirstFocusedEffect(() => {
    getLabelList();
    getAuthProject();
    postMessage({
      type: 'CODESCAN_INDEX_WORKSPACE',
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [postMessage]);

  const handleUpdateTag = () => {
    const tags: FilterTag[] = [];
    view?.value && tags.push({ key: '视图', description: view.label });
    status?.value && tags.push({ key: '状态', description: status.label });
    repo?.value && tags.push({ key: '仓库', description: repo.label });
    if (reviewers?.length) {
      tags.push({
        key: 'Reviewer',
        description:
          reviewers.length > 1 ? `${reviewers.length}人` : reviewers[0].label,
        detail: reviewers.map((item) => item.label).join(','),
      });
    }
    if (authors?.length) {
      tags.push({
        key: 'Author',
        description:
          authors.length > 1 ? `${authors.length}人` : authors[0].label,
        detail: authors.map((item) => item.label).join(','),
      });
    }
    if (labels?.length) {
      tags.push({
        key: '标签',
        description: labels.length > 1 ? `${labels.length}个` : labels[0].label,
        detail: labels.map((item) => item.label).join(','),
      });
    }
    title && tags.push({ key: '标题', description: title });
    sequenceId && tags.push({ key: 'ID', description: sequenceId });
    onUpdateTag(tags);
  };

  const onKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLTextAreaElement | HTMLDivElement>) => {
      if (event.key === 'Enter') {
        // data-focus-visible 表示当前获取焦点的编辑框或下拉框元素，如果下一个元素存在说明下拉框是展开状态
        const isMenuOpen = ref.current?.querySelector(
          '[data-focus-visible]',
        )?.nextElementSibling;
        if (isMenuOpen) return;
        onConfirm();
      }
    },
    [onConfirm],
  );

  const getAuthProject = React.useCallback(async () => {
    if (!username) return;
    try {
      setLoadingUser(true);
      // 获取用户所有有权限的组
      const groupsRes = await authRequest.get(
        `/api/v1/users/@${username}/groups`,
      );
      const groups = _.get(groupsRes, 'data.items') || [];
      setProjects(groups);
      if (!groups.length) return;
      const filterdGroup = groups
        .filter((item: any) => !item.type && item.project)
        .map((item: any) => item.project);
      const groupNames = _.uniq(filterdGroup);

      // 获取所有组的用户
      const res = await authRequest.get(`/api/v1/users`, {
        params: {
          'groups.type_isnull': true,
          'groups.project': groupNames,
        },
      });
      const data = _.filter(_.get(res, 'data.items') || [], (item: any) => {
        return item.status !== 2 && [1, 2].includes(item.type);
      });
      setUserList(data);
    } catch (error) {
      console.error('getAuthProject error:', error);
    } finally {
      setLoadingUser(false);
    }
  }, [username]);

  /**
   * reviewerOptions：根据输入的 reviewerSearchKey 来搜索用户
   * 1. 如果没有输入，则返回空数组
   * 2. 如果输入了，则根据输入的关键字来搜索用户
   * 3. 最多返回 10 条数据
   * 4. 返回的数据格式为 { label: 'fullname(name)', value: 'name' }
   */
  const reviewerOptions = React.useMemo(() => {
    const key = reviewerSearchKey.trim().toLocaleLowerCase();
    return userList
      .filter((item) => {
        return (
          item.name?.toLocaleLowerCase().includes(key) ||
          item.fullname?.toLocaleLowerCase().includes(key)
        );
      })
      .map((item) => {
        return {
          label: `${item.fullname}(${item.name})`,
          value: item.name,
        };
      })
      .slice(0, 10);
  }, [userList, reviewerSearchKey]);

  const authorOptions = React.useMemo(() => {
    const key = authorSearchKey.trim().toLocaleLowerCase();
    return userList
      .filter((item) => {
        return (
          item.name?.toLocaleLowerCase().includes(key) ||
          item.fullname?.toLocaleLowerCase().includes(key)
        );
      })
      .map((item) => {
        return {
          label: `${item.fullname}(${item.name})`,
          value: item.name,
        };
      })
      .slice(0, 10);
  }, [userList, authorSearchKey]);

  const labelOptions = React.useMemo(() => {
    return _.map(labelList, (item) => {
      return {
        label: item,
        value: item,
      };
    });
  }, [labelList]);

  const getLabelList = React.useCallback(async () => {
    try {
      setLoadingLabel(true);
      const res = await proxyRequest(
        {
          method: 'get',
          requestUrl: getRequestUrl(`${TEAM_REVIEW_API_URL}/review_requests`, {
            _sort_by: '-create_time',
            _exclude: 'diff',
          }),
        },
        60000,
        true,
      );
      const project = _.get(res, 'items[0].project') || '';
      if (!project) return;

      const config = await proxyRequest(
        {
          method: 'get',
          requestUrl: `${TEAM_REVIEW_API_URL}/review_requests/configs`,
          requestHeaders: {
            'x-auth-project': project,
          },
        },
        60000,
        true,
      );
      const labelSet = new Set<string>();
      _.forEach(_.get(config, 'items'), (item: any) => {
        _.forEach(item.labels, (label) => {
          if (label.title.trim()) {
            labelSet.add(label.title.trim());
          }
        });
      });
      const labels = Array.from(labelSet).sort();
      setLabelList([NO_LABEL_TITLE, ...labels]);
    } catch (err) {
      setLabelList([NO_LABEL_TITLE]);
    } finally {
      setLoadingLabel(false);
    }
  }, []);

  const backupFilter = React.useCallback(() => {
    setBackup({
      view,
      repo,
      status,
      reviewers,
      authors,
      labels,
      title,
      sequenceId,
    });
  }, [view, repo, status, reviewers, authors, labels, title, sequenceId]);

  const reset = () => {
    setView(DEFAULT_VIEW);
    setRepo(undefined);
    setStatus(DEFAULT_STATUS);
    setReviewers([]);
    setAuthors([]);
    setLabels([]);
    setTitle('');
    setSequenceId('');
  };

  const dealCancel = () => {
    // 恢复到备份状态
    setView(backup.view);
    setRepo(backup.repo);
    setStatus(backup.status);
    setReviewers(backup.reviewers);
    setAuthors(backup.authors);
    setLabels(backup.labels);
    setTitle(backup.title);
    setSequenceId(backup.sequenceId);
    onCancel();
  };

  const quickFilterRef = React.useRef<HTMLDivElement>(null);
  useOutsideClick({
    ref: quickFilterRef,
    handler: (e: Event) => {
      if (!quickFilterVisible) return;
      if (portalRef.current?.contains(e.target as Node)) {
        return;
      }

      setView(backup.view);
      setRepo(backup.repo);
      setStatus(backup.status);
      setReviewers(backup.reviewers);
      setAuthors(backup.authors);
      setLabels(backup.labels);
      setTitle(backup.title);
      setSequenceId(backup.sequenceId);
      onQuickFilterCancel?.();
    },
  });

  const repoOptions = React.useMemo(() => {
    return _.map(repoList, (item: string) => ({ label: item, value: item }));
  }, [repoList]);

  // Render
  const renderViewField = () => {
    return (
      <Box flex={1}>
        <Select
          inputId="chakra-react-select-view"
          onFocus={(e) => {
            e.stopPropagation();
          }}
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          size="sm"
          placeholder="请选择视图"
          options={REVIEW_TYPE_DATA.data}
          value={view}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={quickFilterVisible && quickFilterTargetField === '视图'}
          openMenuOnFocus
          onChange={(val) => {
            setView(val as GroupValue);
            if (val?.value === REVIEW_TYPE_DATA.needreview) {
              const user = _.find(userList, (item) => item.name === username);
              if (user) {
                setReviewers([
                  {
                    label: `${user.fullname}(${user.name})`,
                    value: user.name,
                  },
                ]);
              }
            }
            if (val?.value === REVIEW_TYPE_DATA.mycreate) {
              const user = _.find(userList, (item) => item.name === username);
              if (user) {
                setAuthors([
                  {
                    label: `${user.fullname}(${user.name})`,
                    value: user.name,
                  },
                ]);
              }
            }
          }}
        />
      </Box>
    );
  };

  const renderRepoField = () => {
    return (
      <Box flex={1}>
        <Select
          onFocus={(e) => {
            e.stopPropagation();
          }}
          value={repo}
          onChange={(val) => {
            setRepo(val as GroupValue);
          }}
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          size="sm"
          isClearable
          placeholder="请选择仓库"
          options={repoOptions}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={quickFilterVisible && quickFilterTargetField === '仓库'}
          openMenuOnFocus
          formatOptionLabel={(item) => {
            const formatLabel =
              item.label.startsWith('https://') ||
                item.label.startsWith('http://')
                ? `[git] ${item.label.split('/').slice(-2).join('/')}`
                : item.label;
            return (
              <Tooltip
                label={item.label}
                placement='top'
                hasArrow
                portalProps={{ containerRef: portalRef }}
                zIndex={9999}
              >
                <div className="flex items-center truncate">
                  <span className="truncate" style={{ flex: '0 1 auto' }}>
                    {formatLabel}
                  </span>
                </div>
              </Tooltip>
            );
          }}
          isLoading={loadingRepo}
        />
      </Box>
    );
  };

  const renderStatusField = () => {
    return (
      <Box flex={1}>
        <Select
          onFocus={(e) => {
            e.stopPropagation();
          }}
          value={status}
          onChange={(val) => {
            setStatus(val as GroupValue);
          }}
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          size="sm"
          placeholder="请选择状态"
          options={REQUEST_STATUS}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={quickFilterVisible && quickFilterTargetField === '状态'}
          openMenuOnFocus
        />
      </Box>
    );
  };

  const renderReviewerField = () => {
    return (
      <Box flex={1}>
        <Select
          value={reviewers}
          onFocus={(e) => {
            e.stopPropagation();
          }}
          onChange={(val) => {
            setReviewers(val as GroupValue[]);
            if (view?.value === REVIEW_TYPE_DATA.needreview) {
              if (val.length !== 1 || val[0].value !== username) {
                const targetView = _.find(REVIEW_TYPE_DATA.data, {
                  value: 'all',
                });
                if (targetView) {
                  setView(targetView);
                }
              }
            }
          }}
          onInputChange={(val) => {
            setReviewerSearchKey(val);
          }}
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          isMulti
          size="sm"
          placeholder="请选择或搜索用户"
          options={reviewerOptions}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={
            quickFilterVisible && quickFilterTargetField === 'Reviewer'
          }
          openMenuOnFocus
          noOptionsMessage={({ inputValue }) => {
            if (inputValue) {
              return '未搜索到用户';
            } else {
              return '请输入邮箱前缀搜索用户';
            }
          }}
          isClearable
          isLoading={loadingUser}
        />
      </Box>
    );
  };

  const renderAuthorField = () => {
    return (
      <Box flex={1}>
        <Select
          value={authors}
          onFocus={(e) => e.stopPropagation()}
          onChange={(val) => {
            setAuthors(val as GroupValue[]);
            if (view?.value === REVIEW_TYPE_DATA.mycreate) {
              if (val.length !== 1 || val[0].value !== username) {
                const targetView = _.find(REVIEW_TYPE_DATA.data, {
                  value: 'all',
                });
                if (targetView) {
                  setView(targetView);
                }
              }
            }
          }}
          onInputChange={(val) => {
            setAuthorSearchKey(val);
          }}
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          isMulti
          size="sm"
          placeholder="请选择或搜索用户"
          options={authorOptions}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={quickFilterVisible && quickFilterTargetField === 'Author'}
          openMenuOnFocus
          noOptionsMessage={({ inputValue }) => {
            if (inputValue) {
              return '未搜索到用户';
            } else {
              return '请输入邮箱前缀搜索用户';
            }
          }}
          isClearable
          isLoading={loadingUser}
        />
      </Box>
    );
  };

  const renderLabelField = () => {
    return (
      <Box flex={1}>
        <Select
          onFocus={(e) => e.stopPropagation()}
          value={labels}
          onChange={(val) => {
            setLabels(val as GroupValue[]);
          }}
          isMulti
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          size="sm"
          placeholder="请选择Issue标签"
          options={labelOptions}
          menuPortalTarget={portalRef.current}
          styles={{ menuPortal: getSelectMenuPortal }}
          chakraStyles={{ dropdownIndicator: getSelectDropdownIndicStyles }}
          components={{ IndicatorSeparator: () => null }}
          autoFocus={quickFilterVisible && quickFilterTargetField === '标签'}
          openMenuOnFocus
          isClearable
          isLoading={loadingLabel}
        />
      </Box>
    );
  };

  const renderTitleField = () => {
    return (
      <Box flex={1}>
        <Input
          value={title}
          onChange={(event) => {
            setTitle(event.target.value);
          }}
          size="sm"
          placeholder="请输入标题"
          autoFocus={quickFilterVisible && quickFilterTargetField === '标题'}
        />
      </Box>
    );
  };

  const renderIdField = () => {
    return (
      <Box flex={1}>
        <Input
          id="chakra-react-select-id"
          value={sequenceId}
          onChange={(event) => {
            setSequenceId(event.target.value);
          }}
          size="sm"
          placeholder="请输入ID"
          autoFocus={quickFilterVisible && quickFilterTargetField === 'ID'}
        />
      </Box>
    );
  };

  const renderBranchField = () => {
    return <Box flex={1}>
      <Input
        value={branch}
        onChange={(event) => {
          setBranch(event.target.value);
        }}
        size="sm"
        placeholder="请输入分支"
        autoFocus={quickFilterVisible && quickFilterTargetField === '分支'}
      />
    </Box>
  }

  return (
    <>
      <Box
        ref={portalRef}
        position="fixed"
        top={0}
        left={0}
        right={0}
        bottom={0}
        pointerEvents="none"
        zIndex={9999}
      />
      <Box
        className={clsx(
          styles['request-filter'],
          'flex flex-col rounded max-h-[calc(100vh-100px)]',
          !visible && 'overflow-hidden',
        )}
        {...(!visible
          ? { style: { height: '0', padding: '0', border: 'none' } }
          : {})}
        onClick={(e) => {
          e.stopPropagation();
        }}
        ref={ref}
        onKeyDown={onKeyDown}
        bg="themeBgColor"
      >
        <Box
          flex="1"
          overflowY="auto"
          px="5"
          py="4"
          className="show-scrollbar space-y-3"
        >
          <FormControl>
            <FormLabel>常用视图</FormLabel>
            {renderViewField()}
          </FormControl>
          <FormControl>
            <FormLabel>仓库</FormLabel>
            {renderRepoField()}
          </FormControl>
          <FormControl>
            <FormLabel>状态</FormLabel>
            {renderStatusField()}
          </FormControl>
          <FormControl>
            <FormLabel>Reviewer</FormLabel>
            {renderReviewerField()}
          </FormControl>
          <FormControl>
            <FormLabel>Author</FormLabel>
            {renderAuthorField()}
          </FormControl>
          <FormControl>
            <FormLabel>Issue 标签</FormLabel>
            {renderLabelField()}
          </FormControl>
          <FormControl>
            <FormLabel>Review Requests 标题</FormLabel>
            {renderTitleField()}
          </FormControl>
          <FormControl>
            <FormLabel>Review Request ID</FormLabel>
            {renderIdField()}
          </FormControl>
          <FormControl>
            <FormLabel>分支</FormLabel>
            {renderBranchField()}
          </FormControl>
          {/* <FormControl >
            <FormLabel>创建时间</FormLabel>
            <Datepicker
              inputStyles={{
                fontSize: 'var(--chakra-fontSizes-sm)',
                height: 'var(--chakra-sizes-8)',
                borderRadius: 'var(--chakra-radii-sm)',
              }}
              placeholder="请选择开始时间"
              value={createFrom}
              onChange={(val) => setCreateFrom(val)}
            />
            <Datepicker
              placeholder="请选择结束时间"
              inputStyles={{
                marginTop: 12,
                fontSize: 'var(--chakra-fontSizes-sm)',
                height: 'var(--chakra-sizes-8)',
                borderRadius: 'var(--chakra-radii-sm)',
              }}
              value={createTo}
              onChange={(val) => setCreateTo(val)}
            />
          </FormControl> */}
        </Box>

        <Box
          py="3"
          px="5"
          borderTop="1px solid"
          borderColor="rgba(255, 255, 255, 0.1)"
          bg="themeBgColor"
        >
          <div className="text-right">
            <Button
              color="blue.300"
              size="sm"
              className="mr-2"
              onClick={() => onConfirm()}
            >
              确认
            </Button>
            <Button
              className="mr-2"
              variant="outline"
              size="sm"
              onClick={() => reset()}
            >
              清空
            </Button>
            <Button variant="outline" size="sm" onClick={() => dealCancel()}>
              取消
            </Button>
          </div>
        </Box>
      </Box>

      {/* QuickFilterForm */}
      {quickFilterVisible && onQuickFilterConfirm && onQuickFilterCancel && (
        <Box
          ref={quickFilterRef}
          className="absolute rounded z-[1000] w-[300px] text-left px-3 py-4"
          style={{
            left: quickFilterPosition?.x,
            top: quickFilterPosition?.y,
            border: '1px solid rgba(255, 255, 255, 0.16)',
            boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
            background: 'var(--chakra-colors-themeBgColor)',
          }}
          onClick={(e) => e.stopPropagation()}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              onQuickFilterConfirm?.();
            }
          }}
          bg="themeBgColor"
        >
          <Box className="flex items-center gap-2">
            {quickFilterTargetField === '视图' && renderViewField()}
            {quickFilterTargetField === '仓库' && renderRepoField()}
            {quickFilterTargetField === '状态' && renderStatusField()}
            {quickFilterTargetField === 'Reviewer' && renderReviewerField()}
            {quickFilterTargetField === 'Author' && renderAuthorField()}
            {quickFilterTargetField === '标签' && renderLabelField()}
            {quickFilterTargetField === '标题' && renderTitleField()}
            {quickFilterTargetField === 'ID' && renderIdField()}
            {quickFilterTargetField === '分支' && renderBranchField()}

            <Button
              color="blue.300"
              variant="outline"
              size="sm"
              onClick={onQuickFilterConfirm}
            >
              确认
            </Button>
          </Box>
        </Box>
      )}
    </>
  );
});

interface TeamReiviewProps {
  setTeamReviewStatus: (status: TRStatusType) => void;
  setOperateReviewInfo: (info: any, combine?: boolean) => void;
  operateReviewInfo: {
    data?: {
      _id: string;
    };
    issueMap?: any;
    id?: any; // TODO：确定有这个 id 吗？好像没有赋值
  };
}

// ReviewRequest 组件
const TeamReview = (props: TeamReiviewProps) => {
  const { setTeamReviewStatus, setOperateReviewInfo, operateReviewInfo } =
    props;

  const reviewRequestList = useReviewRequestList();
  const updateReviewRequestList = useUpdateReviewRequestList();

  // reviewRequestId -> issues 的映射
  const [issueMap, setIssueMap] = React.useState<any>({});
  const [loading, setLoading] = React.useState<boolean>(false);
  const [openFilter, setOpenFilter] = React.useState<boolean>(false);
  const username = useAuthStore((state) => state.username);
  const filterRef = React.useRef<any>(null);
  // 由于 sequenceId 查询的时候，某些视图可能会返回多余的数据，需要这个字段来再做一次过滤
  const [filterSequenceId, setFilterSequenceId] = React.useState<string>('');
  const requestIdFromMessage = useCodeReviewStore(
    (state) => state.requestIdFromMessage,
  );
  const setRequestIdFromMessage = useCodeReviewStore(
    (state) => state.setRequestIdFromMessage,
  );
  const [filterTags, setFilterTags] = React.useState<FilterTag[]>([]);

  const [quickFilterVisible, setQuickFilterVisible] = React.useState(false);
  const [quickFilterPosition, setQuickFilterPosition] = React.useState<{
    x: number;
    y: number;
  }>({ x: 0, y: 0 });
  const [quickFilterTargetField, setQuickFilterTargetField] =
    React.useState<string>('');

  const [currentPage, setCurrentPage] = React.useState(1);
  const [hasMore, setHasMore] = React.useState(true);
  const [scrollLoading, setScrollLoading] = React.useState(false);
  const lastParams = React.useRef<any>({});

  const { toast } = useCustomToast();

  // 初始化的时候先请求一次数据
  useFirstFocusedEffect(() => {
    setLoading(true);
    filterRef.current?.init();
  }, []);

  const getRequestData = React.useCallback(
    (params: any, page = 1) => {
      const commonQuery: any = {
        _num: PAGE_SIZE,
        _page: page,
        _exclude: 'diff',
        _embed: 'issues',
        _sort_by: '-create_time',
        // 筛选条件
        address: params.repo,
        status: params.status,
        'reviewers.name': params.reviewers,
        'creator.name': params.authors,
        issue_label: params.labels,
        title: params.title,
        sequenceId: params.sequenceId,
        branch: params.branch,
      };

      const requestUrl = [
        REVIEW_TYPE_DATA.relateme,
        REVIEW_TYPE_DATA.waitapprove,
        REVIEW_TYPE_DATA.myissue,
        REVIEW_TYPE_DATA.mydiscuss,
      ].includes(params.view)
        ? `${TEAM_REVIEW_API_URL}/review_requests/related_me`
        : `${TEAM_REVIEW_API_URL}/review_requests`;

      const viewQueryMap: Record<string, any> = {
        [REVIEW_TYPE_DATA.needreview]: { 'reviewers.name': username },
        [REVIEW_TYPE_DATA.mycreate]: { 'creator.name': username },
        [REVIEW_TYPE_DATA.myissue]: { assigned_issue: 'true' },
        [REVIEW_TYPE_DATA.mydiscuss]: { commented_issue: 'true' },
        [REVIEW_TYPE_DATA.waitapprove]: { wait_approve: 'true' },
        [REVIEW_TYPE_DATA.all]: { admin_type: 'true' },
      };

      const p = {
        ...commonQuery,
        ...(_.get(viewQueryMap, params.view) || {}),
      };
      const result = {
        method: 'get',
        requestUrl: getRequestUrl(requestUrl, p),
      };

      // 存储搜索条件，用于详情切换rr
      delete p._embed;
      localStorage.setItem(
        RR_LIST_SEARCH_CONFIG_KEY,
        JSON.stringify({
          url: requestUrl,
          params: p,
        }),
      );

      return result;
    },
    [username],
  );

  const getReviewRequests = React.useCallback(
    (params: any, quiet = false) => {
      !quiet && setLoading(true);
      lastParams.current = params;
      proxyRequest(getRequestData(params), 60000, true)
        .then((res: any) => {
          const data = _.get(res, 'items') || [];
          const filtedData = data.filter((item: any) =>
            filterSequenceId ? item.sequenceId === filterSequenceId : true,
          );
          const map = data.reduce((obj: any, item: any) => {
            const { _id = '', issues } = item || {};
            obj[_id] = issues;
            return obj;
          }, {});
          setIssueMap(map);
          updateReviewRequestList(filtedData, quiet);
          setCurrentPage(1);
          setHasMore(true);
        })
        .catch(() => {
          if (!quiet) {
            updateReviewRequestList([]);
          }
        })
        .finally(() => {
          !quiet && setLoading(false);
        });
    },
    [filterSequenceId, getRequestData, updateReviewRequestList],
  );

  const loadMore = React.useCallback(
    (page: number) => {
      setScrollLoading(true);
      proxyRequest(getRequestData(lastParams.current, page), 60000, true)
        .then((res) => {
          const data = _.get(res, 'items') || [];
          const filtedData = data.filter((item: any) =>
            filterSequenceId ? item.sequenceId === filterSequenceId : true,
          );
          const map = data.reduce((obj: any, item: any) => {
            const { _id = '', issues } = item || {};
            obj[_id] = issues;
            return obj;
          }, {});
          setIssueMap((prev: any) => ({ ...prev, ...map }));
          updateReviewRequestList(filtedData, true);
          setCurrentPage(page);
          setHasMore(data.length > 0);
        })
        .finally(() => {
          setScrollLoading(false);
        });
    },
    [getRequestData, filterSequenceId, updateReviewRequestList],
  );

  const handlePostMessage = React.useCallback((event: MessageEvent) => {
    const message = event.data;
    switch (message.type) {
      case 'TEAM_REVIEW_REFRESH': {
        filterRef.current?.search(true);
        break;
      }
      default: {
        break;
      }
    }
  }, []);

  // 在插件收到消息的时候，用来跳转到详情页，只做一次性跳转
  React.useEffect(() => {
    if (reviewRequestList && reviewRequestList.length && requestIdFromMessage) {
      const target = reviewRequestList.find(
        (item) => item._id === requestIdFromMessage,
      );
      if (target) {
        setOperateReviewInfo({
          reviewRequestId: target._id,
        });
        setTeamReviewStatus(TRStatusType.info);
        // 一次性跳转，在定位到之后清空
        setRequestIdFromMessage('');
      }
    }
  }, [reviewRequestList, requestIdFromMessage, setRequestIdFromMessage]);

  // postMessage 处理
  React.useEffect(() => {
    window.addEventListener('message', handlePostMessage);
    return () => {
      window.removeEventListener('message', handlePostMessage);
    };
  }, [handlePostMessage]);

  const handleOperationFinish = React.useCallback((e: any) => {
    const { type } = e.detail;
    switch (type) {
      case TRStatusType.add: {
        toast({
          title: '创建成功',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
        break;
      }
      case TRStatusType.edit: {
        toast({
          title: '修改成功',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
        break;
      }
      case TRStatusType.open: {
        toast({
          title: '已打开',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
        break;
      }
      case TRStatusType.close: {
        toast({
          title: '已关闭',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
        break;
      }
      case TRStatusType.delete: {
        toast({
          title: '已删除',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
        break;
      }
    }
    filterRef.current?.search(true);
  }, []);

  React.useEffect(() => {
    window.addEventListener('reviewOperationFinish', handleOperationFinish);
    return () => {
      window.removeEventListener(
        'reviewOperationFinish',
        handleOperationFinish,
      );
    };
  }, [handleOperationFinish]);

  // 标记 reviewRequest 已读
  const onReadRequest = (id: string) => {
    if (!id) return;
    proxyRequest(
      {
        method: 'put',
        requestUrl: `${TEAM_REVIEW_API_URL}/review_requests/${id}/reviewers/is_read`,
        requestData: {
          isRead: true,
          reviewerName: username,
        },
      },
      60000,
    ).then(() => {
      // OPTIMIZED: 改用 context 来同步
      window.postMessage(
        {
          type: 'TEAM_REVIEW_REFRESH',
        },
        '*',
      );
    });
  };

  const handleQuickFilterConfirm = React.useCallback(() => {
    setQuickFilterVisible(false);
    setTimeout(() => {
      filterRef.current?.search();
    }, 0);
  }, []);

  const handleQuickFilterCancel = React.useCallback(() => {
    setQuickFilterVisible(false);
  }, []);

  const handleFilterTagClick = React.useCallback(
    (event: React.MouseEvent, tag: FilterTag) => {
      event.stopPropagation();
      const rect = event.currentTarget.getBoundingClientRect();
      const windowWidth = window.innerWidth;
      const quickFilterWidth = 300;
      const adjustedX =
        rect.left + quickFilterWidth > windowWidth
          ? windowWidth - quickFilterWidth - 32
          : rect.left - 16;

      setQuickFilterPosition({
        x: adjustedX,
        y: rect.bottom - 40,
      });
      setQuickFilterTargetField(tag.key);
      setQuickFilterVisible(true);
    },
    [],
  );

  const holderHeight = React.useMemo(() => {
    return 200 - reviewRequestList?.length * 50 > 0
      ? 200 - reviewRequestList?.length * 50
      : 0;
  }, [reviewRequestList?.length]);

  return (
    <div className="relative" style={{ border: 'none' }}>
      <Box className="absolute w-full -top-9 left-0 flex justify-end">
        <Tooltip label="刷新">
          <IconButton
            aria-label="刷新"
            size="xs"
            icon={<Icon as={TbRefresh} w="16px" h="16px" />}
            bg="none"
            color="text.default"
            onClick={(e) => {
              e.stopPropagation();
              setLoading(true);
              filterRef.current?.search();
            }}
          />
        </Tooltip>
        <Tooltip label="创建Review">
          <IconButton
            aria-label="创建"
            size="xs"
            icon={<Icon as={TbPlus} w="18px" h="18px" />}
            bg="none"
            color="text.default"
            onClick={(e) => {
              e.stopPropagation();
              // 切换状态创建 reviewRequest，更新父组件的 operateReviewInfo
              setTeamReviewStatus(TRStatusType.add);
              setOperateReviewInfo({});
            }}
          />
        </Tooltip>
        <div
          className={clsx('inline-block', !quickFilterVisible && 'relative')}
          onClick={(e) => {
            e.stopPropagation();
            setOpenFilter(!openFilter);
          }}
        >
          <Tooltip label="筛选Review">
            <IconButton
              aria-label="筛选"
              size="xs"
              icon={<Icon as={TbFilter} w="16px" h="16px" />}
              bg="none"
              color="text.default"
            />
          </Tooltip>
          <RequestFilter
            ref={filterRef}
            visible={openFilter}
            onConfirm={() => {
              filterRef.current?.search();
              setOpenFilter(false);
            }}
            onCancel={() => {
              setOpenFilter(false);
            }}
            onUpdateTag={(val) => {
              setFilterTags(val);
            }}
            setFilterSequenceId={setFilterSequenceId}
            onSearch={getReviewRequests}
            quickFilterVisible={quickFilterVisible}
            quickFilterPosition={quickFilterPosition}
            quickFilterTargetField={quickFilterTargetField}
            onQuickFilterConfirm={handleQuickFilterConfirm}
            onQuickFilterCancel={handleQuickFilterCancel}
          />
        </div>
      </Box>
      <div
        className="pb-4 overflow-y-auto"
        style={{ maxHeight: 'calc(100vh - 90px)' }}
        onScroll={(e) => {
          const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;
          if (scrollLoading || !hasMore) return;
          if (scrollHeight - scrollTop <= clientHeight + 20) {
            loadMore(currentPage + 1);
          }
        }}
      >
        <div className="flex flex-wrap gap-1 mb-2">
          {filterTags.map((tag) => (
            <Tooltip
              key={tag.key}
              label={<div className='break-all'>
                {tag.key}: {tag.detail || tag.description}
              </div>}
            >
              <Tag
                className="cursor-pointer hover:text-[#786fff] hover:bg-[#786fff]/20 transition"
                onClick={(e) => handleFilterTagClick(e, tag)}
              >
                <span className="mr-1">{tag.key}:</span>
                <span className="max-w-[100px] truncate">
                  {tag.description}
                </span>
                <TbChevronDown />
              </Tag>
            </Tooltip>
          ))}
          <Tooltip label="标签展示当前列表查询条件，您可以点击标签快速编辑筛选条件">
            <span>
              <Icon
                as={TbHelpCircle}
                w="18px"
                h="18px"
                className="hover:opacity-80"
                style={{ position: 'relative', top: '-1px' }}
              />
            </span>
          </Tooltip>
        </div>
        {loading ? (
          <div>数据加载中，请稍等...</div>
        ) : reviewRequestList.length ? (
          <div>
            {_.map(reviewRequestList, (item: any) => {
              const {
                title,
                status,
                reviewers,
                create_time,
                _id,
                creator,
                update_time,
                sequenceId,
                failed_reason,
              } = item;
              const openIssue = _.filter(issueMap?.[_id], {
                status: 'open',
              });
              const closeIssue = _.filter(issueMap?.[_id], (issue) => {
                return ['closed', 'ignore'].includes(issue.status);
              });
              const matchReviewer = _.find(reviewers, { name: username });
              const needRead = matchReviewer ? !matchReviewer.isRead : false;
              const aiReview = _.find(reviewers, { name: 'AI_REVIEWER' });
              const filteredReviewers = _.filter(reviewers, (item) => {
                return item.name !== 'AI_REVIEWER';
              });

              const renderReviewerStatus = () => {
                return (
                  <>
                    <Tooltip
                      label={_.map(reviewers, (reviewer: any) => (
                        <div key={reviewer.name}>
                          {reviewer.name === 'AI_REVIEWER'
                            ? 'AI'
                            : reviewer.fullname}{' '}
                          {(REVIEWER_STATUS_MAP as any)[reviewer.reviewStatus]
                            ?.label || ''}
                        </div>
                      ))}
                    >
                      <span className="mr-2">
                        {/* 空span避免样式错乱 */}
                        <span />
                        {aiReview && (
                          <span
                            className={styles['ai-review-avatar']}
                            style={{
                              borderColor: (REVIEWER_STATUS_MAP as any)[
                                aiReview.reviewStatus
                              ]?.color,
                            }}
                          >
                            AI
                          </span>
                        )}
                        {_.map(
                          filteredReviewers?.slice(0, aiReview ? 2 : 3),
                          (reviewer: any) => {
                            return (
                              <span
                                key={reviewer.name}
                                className={styles['reviewer-avatar']}
                                style={{
                                  borderColor: (REVIEWER_STATUS_MAP as any)[
                                    reviewer.reviewStatus
                                  ]?.color,
                                }}
                              >
                                {(
                                  reviewer?.fullname?.[
                                  reviewer?.fullname?.length - 1
                                  ] || ''
                                ).toUpperCase()}
                              </span>
                            );
                          },
                        )}
                        {filteredReviewers?.length > (aiReview ? 2 : 3) && (
                          <span className={styles['reviewer-avatar']}>···</span>
                        )}
                      </span>
                    </Tooltip>
                    {openIssue.length > 0 && (
                      <Tooltip label="状态为 open 的数量">
                        <span
                          className={`${styles['issue-num-icon']} waring mr-2 relative`}
                        >
                          <Icon as={TbExclamationMark} />
                          {openIssue.length}
                        </span>
                      </Tooltip>
                    )}
                    {closeIssue.length > 0 && (
                      <Tooltip label="状态为 closed 或 ignore 的数量">
                        <span
                          className={`${styles['issue-num-icon']} success mr-2 relative`}
                        >
                          <Icon as={TbCheck} />
                          {closeIssue.length}
                        </span>
                      </Tooltip>
                    )}
                  </>
                );
              };

              return (
                <div
                  key={_id}
                  className={`hover:bg-[#ffffff29] ${operateReviewInfo?.data?._id === _id ? 'bg-[#ffffff29]' : ''} cursor-pointer pt-1 pb-1 pl-2 pr-2`}
                  onClick={() => {
                    // 选中某个 ReviewRequest 时，更新当前状态和父组件的 operateReviewInfo
                    setTeamReviewStatus(TRStatusType.info);
                    setOperateReviewInfo({ reviewRequestId: _id });
                    // 更新已读状态
                    needRead && onReadRequest(_id);
                  }}
                >
                  <div className="flex items-center gap-2 min-[420px]:gap-1">
                    <div className="flex-1 min-w-10 flex items-center gap-1">
                      <Tooltip label={title}>
                        <span className="truncate">{title}</span>
                      </Tooltip>
                      {needRead && <span className={styles['red-point']} />}
                    </div>
                    <span className="flex-shrink-0 max-[420px]:hidden">
                      <Tooltip
                        isDisabled={status !== ReviewRequestStatus.Failed}
                        label={
                          <div className="break-all whitespace-pre-wrap">
                            {failed_reason || '--'}
                            ，请在右侧更多操作中重试，或联系 Codemaker 值班处理
                          </div>
                        }
                      >
                        <span
                          className={clsx('mr-2', {
                            'text-[#786fff]':
                              status === ReviewRequestStatus.Initializing,
                            'text-[#ff4747]':
                              status === ReviewRequestStatus.Failed,
                            'text-[#8e8e8e]':
                              status !== ReviewRequestStatus.Initializing &&
                              status !== ReviewRequestStatus.Failed,
                          })}
                        >
                          {REVIEW_STATUS_LABELS[
                            status as ReviewRequestStatus
                          ] || '--'}
                        </span>
                      </Tooltip>
                    </span>
                    <span className="flex-shrink-0 flex items-center max-[300px]:hidden">
                      {renderReviewerStatus()}
                    </span>
                    <ActionPopover
                      setOperateReviewInfo={setOperateReviewInfo}
                      setTeamReviewStatus={setTeamReviewStatus}
                      data={item || {}}
                      issueMap={issueMap}
                    />
                  </div>
                  <div className="hidden max-[300px]:flex items-center">
                    {renderReviewerStatus()}
                  </div>
                  <div
                    className="flex justify-between gap-8 max-[420px]:hidden"
                    style={{ color: '#8e8e8e' }}
                  >
                    <div className="flex-1 w-0">
                      {(() => {
                        const address = getRepoAddress(item.address);
                        const halfLen = Math.floor(address.length / 2);
                        const titleLeft = address.slice(0, halfLen);
                        const titleRight = address.slice(halfLen);
                        return (
                          <Tooltip label={address}>
                            <div className="flex items-center truncate">
                              <span
                                className="truncate"
                                style={{ flex: '0 1 auto' }}
                              >
                                {titleLeft}
                              </span>
                              <span
                                className="truncate"
                                style={{
                                  flex: '0 1 auto',
                                  textOverflow: 'clip',
                                  direction: 'rtl',
                                  textAlign: 'left',
                                }}
                              >
                                &lrm;{titleRight}&lrm;
                              </span>
                            </div>
                          </Tooltip>
                        );
                      })()}
                    </div>
                    {item?.address.endsWith('.git') && (
                      <Tooltip
                        label={
                          item?.mergeRequestIid
                            ? `${item?.gitSourceBranch} into ${item?.gitTargetBranch}`
                            : item?.svnUrl?.split('.git/')?.[1] || '--'
                        }
                      >
                        <div className="flex items-center gap-1 max-w-[30vw] w-fit truncate">
                          <TbGitBranch className="flex-shrink-0" />
                          {item?.mergeRequestIid ? (
                            <span className="text-[#8e8e8e] truncate">
                              {item?.gitSourceBranch} into{' '}
                              {item?.gitTargetBranch}
                            </span>
                          ) : (
                            <span className="text-[#8e8e8e] truncate">
                              {item?.svnUrl?.split('.git/')?.[1] || '--'}
                            </span>
                          )}
                        </div>
                      </Tooltip>
                    )}
                    {item?.svnUrl.startsWith('svn://') && (
                      <Tooltip
                        label={item?.svnUrl?.split(item.address)?.[1] || '--'}
                      >
                        <div className="flex items-center gap-1 max-w-[30vw] w-fit truncate">
                          <TbGitBranch className="flex-shrink-0" />
                          <span className="text-[#8e8e8e] truncate">
                            {item.svnUrl?.split(item.address)?.[1] || '--'}
                          </span>
                        </div>
                      </Tooltip>
                    )}
                  </div>
                  <div
                    className="flex max-[300px]:hidden"
                    style={{ color: '#8e8e8e' }}
                  >
                    <div className="flex-1">
                      <Tooltip
                        label={DateFormat(
                          (+create_time || 0) * 1000,
                          'YYYY-MM-DD HH:mm',
                        )}
                      >
                        <span>
                          #{sequenceId} 创建于{' '}
                          {timeSince((+create_time || 0) * 1000)} by{' '}
                        </span>
                      </Tooltip>
                      {_.get(creator, 'fullname')}
                    </div>
                    <div className="max-[420px]:hidden">
                      <Tooltip
                        label={DateFormat(
                          (+update_time || 0) * 1000,
                          'YYYY-MM-DD HH:mm',
                        )}
                      >
                        <span>
                          更新于 {timeSince((+update_time || 0) * 1000)}
                        </span>
                      </Tooltip>
                    </div>
                  </div>
                </div>
              );
            })}
            <Box
              className="mt-4"
              display="flex"
              justifyContent="center"
              fontSize="12px"
              color="text.default"
            >
              {scrollLoading ? <Spinner size="sm" /> : null}
              {!hasMore ? <span>没有更多数据了</span> : null}
            </Box>
          </div>
        ) : (
          <div>
            无需要参加的Review，
            <span
              className="cursor-pointer mt-2 hover:opacity-50"
              style={{ color: 'var(--chakra-colors-blue-300)' }}
              onClick={(e) => {
                e.stopPropagation();
                // 切换状态创建 reviewRequest，更新父组件的 operateReviewInfo
                setTeamReviewStatus(TRStatusType.add);
                setOperateReviewInfo({});
              }}
            >
              发起Review Request
            </span>
          </div>
        )}
        {/* 占位 */}
        <div style={{ marginBottom: `${holderHeight}px` }} />
      </div>
    </div>
  );
};

export default TeamReview;

