import { forEach } from 'lodash';
import { proxyRequest } from '../../services/common';
import { TEAM_REVIEW_API_URL } from './const';
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

/**
 * 根据 Tailwind CSS 的优先级规则，自动处理重复或冲突的类名
 * @param inputs 类名
 * @returns 合并后的类名
 */
export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};

export const getRepoAddress = (repo: string) => {
  if (!repo) return repo;
  if (repo.startsWith('svn://')) {
    const svnUrl = repo.replace('svn://', '');
    const index = svnUrl.indexOf('/');
    if (index !== -1) {
      return svnUrl.slice(0, index);
    } else {
      return svnUrl;
    }
  }
  if (repo.includes('.git')) {
    return repo.split('.git')[0] + '.git';
  }
  if (repo.startsWith('ssl:') && repo.includes('-//')) {
    return repo.split('-//')[0];
  }
  return repo;
};

export const formatRepoUrl = (repo: string, type: string) => {
  if (!repo) return repo;
  if (type === 'svn') {
    return repo.replace(/^(https?)/, 'svn');
  }
  if (type === 'p4') {
    return repo.includes('-//') ? repo : `${repo}-//`;
  }
  return normalizeGitUrl(repo);
};

/**
 * 标准化 Git 仓库 URL
 * 将各种格式的 Git URL 转换为标准格式：[protocol]://host.com/path/to/repo.git
 *
 * @param url - 原始 Git URL
 * @returns 标准化后的 URL
 */
export const normalizeGitUrl = (url: string) => {
  if (!url || typeof url !== 'string') {
    return '';
  }

  let normalizedUrl = url.trim();

  // 处理 SSH 格式: ssh://[user@]host[:port]/path/to/repo[.git][/]
  if (normalizedUrl.startsWith('ssh://')) {
    const sshRegex =
      /^ssh:\/\/(?:[^@]+@)?([^:/]+)(?::\d+)?\/(.+?)(?:\.git)?\/?$/;
    const match = normalizedUrl.match(sshRegex);

    if (match) {
      const host = match[1];
      const path = match[2];
      normalizedUrl = `https://${host}/${path}.git`;
      return normalizedUrl;
    }
  }

  // 处理 HTTPS/HTTP 格式: https://[username[:password]@]host[:port]/path/to/repo[.git][/]
  if (
    normalizedUrl.startsWith('https://') ||
    normalizedUrl.startsWith('http://')
  ) {
    const protocol = normalizedUrl.startsWith('https://') ? 'https' : 'http'; // 保留原始协议

    // 匹配并提取各部分
    const httpRegex =
      /^https?:\/\/(?:[^@]+@)?([^:/]+)(?::\d+)?\/(.+?)(?:\.git)?\/?$/;
    const match = normalizedUrl.match(httpRegex);

    if (match) {
      const host = match[1];
      const path = match[2];
      normalizedUrl = `${protocol}://${host}/${path}.git`;
      return normalizedUrl;
    }
  }

  // 如果无法匹配任何已知格式，返回原 URL
  return '';
};

export const getRequestUrl = (url: string, params: Record<string, any>) => {
  const queryParams = new URLSearchParams();
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined && value !== null && value !== '') {
      if (Array.isArray(value)) {
        value.forEach((v) => queryParams.append(key, v));
      } else {
        queryParams.append(key, value);
      }
    }
  }
  return `${url}?${queryParams.toString()}`;
};

export const getUniqueRepo = (
  repoMap: Record<string, string[]>,
  onlyAddress = false,
) => {
  const repoSet = new Set<string>();
  forEach(repoMap, (repos) => {
    repos.forEach((repo) => {
      repoSet.add(onlyAddress ? getRepoAddress(repo) : repo);
    });
  });
  return Array.from(repoSet).sort((a: string, b: string) => {
    return b.localeCompare(a);
  });
};

export const getRepoProjectMap = (repoMap: Record<string, string[]>) => {
  const repoProjectMap: Record<string, string[]> = {};
  forEach(repoMap, (repos, project) => {
    forEach(repos, (repo) => {
      repoProjectMap[repo] = (repoProjectMap[repo] || []) as string[];
      repoProjectMap[repo].push(project);
    });
  });
  return repoProjectMap;
};

/**
 * 根据域名从 repoProjectMap 中查找所有匹配的项目
 * @param repoProjectMap 完整 URL -> 项目数组 的映射
 * @param domain 域名（如 svn-hookstest02.gz.netease.com）
 * @returns 匹配的项目列表（去重）
 */
export const findProjectsForDomain = (
  repoProjectMap: Record<string, string[]>,
  domain: string,
): string[] => {
  if (!domain) return [];

  const projectSet = new Set<string>();

  // 遍历所有完整 URL，找出域名匹配的项目
  Object.entries(repoProjectMap).forEach(([fullUrl, projects]) => {
    const urlDomain = getRepoAddress(fullUrl);
    if (urlDomain === domain) {
      projects.forEach((p) => projectSet.add(p));
    }
  });

  return Array.from(projectSet);
};

/**
 * 检查域名是否有多个项目（需要用户选择）
 * @param repoProjectMap 完整 URL -> 项目数组 的映射
 * @param domain 域名
 * @returns 是否有多个项目
 */
export const isDomainMultiAccessRepo = (
  repoProjectMap: Record<string, string[]>,
  domain: string,
): boolean => {
  const projects = findProjectsForDomain(repoProjectMap, domain);
  return projects.length > 1;
};

/**
 * 根据域名查找第一个匹配的完整 URL
 * @param repoProjectMap 完整 URL -> 项目数组 的映射
 * @param domain 域名
 * @returns 第一个匹配的完整 URL，如果没找到则返回原始域名
 */
export const getFullUrlFromDomain = (
  repoProjectMap: Record<string, string[]>,
  domain: string,
): string => {
  if (!domain) return domain;

  // 如果传入的已经是完整 URL，直接返回
  if (
    domain.startsWith('svn://') ||
    domain.startsWith('ssl:') ||
    domain.startsWith('http://') ||
    domain.startsWith('https://')
  ) {
    return domain;
  }

  // 遍历所有完整 URL，找出域名匹配的第一个
  for (const fullUrl of Object.keys(repoProjectMap)) {
    const urlDomain = getRepoAddress(fullUrl);
    if (urlDomain === domain) {
      return fullUrl;
    }
  }

  // 没找到则返回原始域名
  return domain;
};

export const findProjectsForRepo = (
  repoProjectMap: Record<string, string[]>,
  repoUrl: string,
): string[] => {
  if (!repoUrl) return [];

  // 1. 首先尝试精确匹配
  if (repoProjectMap[repoUrl]) {
    return repoProjectMap[repoUrl];
  }

  // 2. 对于 SVN 和 P4 路径，尝试匹配父目录
  const isSvn = repoUrl.startsWith('svn://');
  const isP4 = /^ssl:.*?-\/\/.+$/.test(repoUrl);

  // 如果 repoUrl 是域名格式（不是 svn:// 或 ssl: 或 http/https 开头），
  // 尝试从 repoProjectMap 中找到完整 URL，收集所有匹配的项目
  if (
    !isSvn &&
    !isP4 &&
    !repoUrl.startsWith('http://') &&
    !repoUrl.startsWith('https://')
  ) {
    const projectSet = new Set<string>();
    const normalizedRepoUrl = repoUrl.replace(/\/$/, '');
    // 遍历所有完整 URL，找出域名匹配的所有项目
    for (const fullUrl of Object.keys(repoProjectMap)) {
      const urlDomain = getRepoAddress(fullUrl);
      // 标准化比较：去掉尾部斜杠
      const normalizedDomain = urlDomain.replace(/\/$/, '');
      if (normalizedDomain === normalizedRepoUrl) {
        // 收集所有匹配的项目
        repoProjectMap[fullUrl].forEach((p) => projectSet.add(p));
      }
    }
    if (projectSet.size > 0) {
      return Array.from(projectSet);
    }
  }

  if (isSvn || isP4) {
    // 标准化路径：确保以 / 结尾
    let normalizedUrl = repoUrl;
    if (!normalizedUrl.endsWith('/')) {
      normalizedUrl += '/';
    }

    if (isSvn) {
      // 处理 SVN 路径: svn://host/path1/path2/
      // 提取 host 和路径部分
      const svnMatch = normalizedUrl.match(/^svn:\/\/([^/]+)(\/.*)?$/);
      if (svnMatch) {
        const host = svnMatch[1];
        const pathPart = svnMatch[2] || '/';

        // 分割路径部分，不包括开头的 /
        const pathSegments = pathPart.substring(1).split('/').filter(Boolean);

        // 如果是域名级别（没有路径），收集所有该域名下的项目
        if (pathSegments.length === 0) {
          const projectSet = new Set<string>();
          const hostPrefix = `svn://${host}/`;
          for (const fullUrl of Object.keys(repoProjectMap)) {
            if (fullUrl.startsWith(hostPrefix)) {
              repoProjectMap[fullUrl].forEach((p) => projectSet.add(p));
            }
          }
          if (projectSet.size > 0) {
            return Array.from(projectSet);
          }
        }

        // 从最深层级开始向上查找
        for (let i = pathSegments.length; i >= 0; i--) {
          const parentPath =
            i === 0
              ? `svn://${host}/`
              : `svn://${host}/${pathSegments.slice(0, i).join('/')}/`;

          if (repoProjectMap[parentPath]) {
            return repoProjectMap[parentPath];
          }
        }
      }
    } else if (isP4) {
      // 处理 P4 路径: ssl:host:port-//depot/path/
      const p4Match = normalizedUrl.match(/^(ssl:[^:]+:\d+-\/\/[^/]+)(\/.*)?$/);
      if (p4Match) {
        const basePath = p4Match[1];
        const pathPart = p4Match[2] || '/';

        // 分割路径部分
        const pathSegments = pathPart.substring(1).split('/').filter(Boolean);

        // 从最深层级开始向上查找
        for (let i = pathSegments.length; i >= 0; i--) {
          const parentPath =
            i === 0
              ? `${basePath}/`
              : `${basePath}/${pathSegments.slice(0, i).join('/')}/`;

          if (repoProjectMap[parentPath]) {
            return repoProjectMap[parentPath];
          }
        }
      }
    }
  }

  // 3. 对于 Git 仓库，尝试标准化后匹配
  const isGitUrl = repoUrl.includes('.git');
  if (isGitUrl) {
    // 尝试不同的 Git URL 变体
    const urlVariants: string[] = [];

    // 原始 URL
    urlVariants.push(repoUrl);

    // 如果以 .git/ 结尾，尝试去掉斜杠
    if (repoUrl.endsWith('.git/')) {
      urlVariants.push(repoUrl.slice(0, -1));
    }

    // 如果包含 .git 但不是以它结尾（例如 .git/some/path），尝试截断到 .git
    const gitIndex = repoUrl.indexOf('.git');
    if (gitIndex !== -1 && gitIndex < repoUrl.length - 4) {
      const baseUrl = repoUrl.substring(0, gitIndex + 4);
      urlVariants.push(baseUrl);
    }

    // 尝试所有变体
    for (const variant of urlVariants) {
      if (repoProjectMap[variant]) {
        return repoProjectMap[variant];
      }
    }
  }

  return [];
};

export const parseHtmlEntities = (text: string) => {
