};

const SECOND = 1000;
const MINUTE = 60 * SECOND;
const HOUR = 60 * MINUTE;
const DAY = 24 * HOUR;
const WEEK = 7 * DAY;
const MONTH = 30 * DAY;
const YEAR = 365 * DAY;

export function timeSince(timestamp: number): string {
  const now = Date.now();
  const timePast = now - timestamp;

  if (timePast < MINUTE) {
    return '刚刚';
  } else if (timePast < HOUR) {
    const minutes = Math.floor(timePast / MINUTE);
    return `${minutes}分钟前`;
  } else if (timePast < DAY) {
    const hours = Math.floor(timePast / HOUR);
    return `${hours}小时前`;
  } else if (timePast < WEEK) {
    const days = Math.floor(timePast / DAY);
    return `${days}天前`;
  } else if (timePast < MONTH) {
    const weeks = Math.floor(timePast / WEEK);
    return `${weeks}周前`;
  } else if (timePast < YEAR) {
    const months = Math.floor(timePast / MONTH);
    return `${months}个月前`;
  } else {
    const years = Math.floor(timePast / YEAR);
    return `${years}年前`;
  }
}

