export interface RetryRRParams {
  title: string;
  svnUrl: string;
  reviewers: any[];
  aiAction?: any;
  redmineIssueId?: string;
  redmineDomain?: string;
  user_review_description?: string;
  use_ai_explain_for_review?: boolean;
  mergeRequestIid?: string;
  gitSourceBranch?: string;
  gitTargetBranch?: string;
  fileList?: any[];
  revisions?: any[];
}

export const retryCreateReviewRequest = async (data: any) => {
  const params: RetryRRParams = {
    title: data.title,
    svnUrl: data.svnUrl,
    reviewers: data.reviewers,
    aiAction: data.aiAction,
    redmineIssueId: data.redmineIssueId,
  };

  if (data.redmineDomain) params.redmineDomain = data.redmineDomain;
  if (data.redmineIssueId) params.redmineIssueId = data.redmineIssueId;
  if (data.user_review_description) {
    params.user_review_description = data.user_review_description;
  }
  if (data.use_ai_explain_for_review) {
    params.use_ai_explain_for_review = data.use_ai_explain_for_review;
  }
  if (data.reviewers) params.reviewers = data.reviewers;

  if (data.mergeRequestIid) {
    params.mergeRequestIid = data.mergeRequestIid;
    params.gitSourceBranch = data.gitSourceBranch;
    params.gitTargetBranch = data.gitTargetBranch;
  } else if (data.fileList?.length) {
    params.fileList = data.fileList;
  } else {
    params.revisions = data.revisions;
  }

  return await proxyRequest(
    {
      method: 'put',
      requestUrl: `${TEAM_REVIEW_API_URL}/review_requests/${data._id}`,
      requestData: params,
    },
    2 * 60 * 1000,
  );
};

/**
 * 标准化 revision 值为字符串，用于统一比较
 * @param revision revision 值 (可能是 string 或 number)
 * @returns 标准化后的字符串
 */
export function normalizeRevision(revision: string | number): string {
  return String(revision);
}

/**
 * 检查两个 revision 是否相等（忽略类型差异）
 * @param a revision A
 * @param b revision B
 * @returns 是否相等
 */
export function isRevisionEqual(
  a: string | number,
  b: string | number,
): boolean {
  return normalizeRevision(a) === normalizeRevision(b);
}

/**
 * 标准化 revision 数组，确保所有元素都是字符串类型
 * @param revisions revision 数组
 * @returns 标准化后的字符串数组
 */
export function normalizeRevisionArray(
  revisions: (string | number)[],
): string[] {
  return revisions.map(normalizeRevision);
}

/**
 * 在 commit 数组中查找与指定 revision 匹配的 commit（忽略类型差异）
 * @param commits commit 数组
 * @param targetRevision 要查找的 revision
 * @returns 找到的 commit 对象
 */
export function findCommitByRevision(
  commits: any[],
  targetRevision: string | number,
): any | undefined {
  return commits.find((commit) =>
    isRevisionEqual(commit.revision, targetRevision),
  );
}

/**
 * 合并两个 revision 数组并去重（忽略类型差异）
 * @param array1 第一个 revision 数组
 * @param array2 第二个 revision 数组
 * @returns 合并后的去重数组
 */
export function mergeUniqueRevisions(
  array1: (string | number)[],
  array2: (string | number)[],
): string[] {
  const normalized1 = normalizeRevisionArray(array1);
  const normalized2 = normalizeRevisionArray(array2);
  return Array.from(new Set([...normalized1, ...normalized2]));
}

/**
 * 检查 revision 是否在数组中存在（忽略类型差异）
 * @param revisions revision 数组
 * @param targetRevision 要检查的 revision
 * @returns 是否存在
 */
export function hasRevisionInArray(
  revisions: (string | number)[],
  targetRevision: string | number,
): boolean {
  const normalizedTarget = normalizeRevision(targetRevision);
  return revisions.some(
    (revision) => normalizeRevision(revision) === normalizedTarget,
  );
}

/**
 * 从 revision 数组中移除指定的 revision（忽略类型差异）
 * @param revisions 原始 revision 数组
 * @param targetRevision 要移除的 revision
 * @returns 移除后的数组
 */
export function removeRevisionFromArray(
  revisions: string[],
  targetRevision: string | number,
): string[] {
  const normalizedTarget = normalizeRevision(targetRevision);
  return revisions.filter(
    (revision) => normalizeRevision(revision) !== normalizedTarget,
  );
}

/**
 * 将文件转换为 Base64
 * @param file 要转换的文件
 * @returns Promise<string>
 */
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // 移除 data:*/*;base64, 前缀，只保留 base64 数据
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

/**
 * 上传文件到 Review 文件服务
 * @param file 要上传的文件
 * @param project 项目名称
 * @returns Promise<{ file_id: string, filename }>
 */
export const uploadReviewFile = async (file: File, project: string) => {
  const base64Content = await fileToBase64(file);
  return await proxyRequest(
    {
      method: 'post',
      requestUrl: `${TEAM_REVIEW_API_URL}/codex_fs/files`,
      requestData: {
        __fileUpload: true,
        file: {
          filename: file.name,
          content: base64Content,
          contentType: file.type || 'application/octet-stream',
          size: file.size,
        },
      },
      requestHeaders: {
        'X-Codex-Fs-Bucket': 'ai_review',
        'X-Auth-Project': project,
      },
    },
    2 * 60 * 1000,
  );
};

/**
 * @name 执行函数时，忽略异常
 * @param func
 */
export const execFuncWithoutException = (func: () => void) => {
  try {
    func?.();
  } catch (e) {
    /* empty */
  }
};

/**
 * 从 SVN URL 中提取分支路径
 * 例如: "svn://svn-dep35.gz.netease.com/svn/develop/" -> "/svn/develop/"
 */
export const extractBranchFromPath = (path: string): string => {
  try {
    // 切掉 svn:// 前缀
    const withoutProtocol = path.replace(/^svn:\/\//, '');
    // 找到第一个 / 的位置（域名后面的斜杠）
    const firstSlashIndex = withoutProtocol.indexOf('/');
    if (firstSlashIndex === -1) {
      return path; // 如果没有找到，返回原始路径
    }
    // 取域名后面的部分作为分支路径
    return withoutProtocol.slice(firstSlashIndex);
  } catch {
    return path;
  }
};

/**
 * 获取仓库 URL 的分组前缀
 *
 * 分组策略：
 * - SVN 仓库: 保留到 /svn 层级
 *   例如: svn://svn.gz.netease.com/svn/xxx/yyy => svn://svn.gz.netease.com/svn
 *
 * - P4 仓库: 保留到 depot 层级
 *   例如: ssl:p4server:1666-//depot/project/main => ssl:p4server:1666-//depot
 *
 * - Git 仓库 (GitLab, GitHub 等): 只保留域名
 *   例如: https://gitlab.gz.netease.com/dap/aigcpro/xxx => https://gitlab.gz.netease.com
 *   例如: https://github.com/facebook/react.git => https://github.com
 *
 * @param url - 仓库 URL
 * @returns 分组前缀，如果无法提取则返回原 URL
 */
export const getRepoGroupPrefix = (url: string): string => {
  if (!url) return url;

  // SVN: 保留到 /svn 层级
  if (url.startsWith('svn://')) {
    const segments = url.split('/');
    if (segments.length >= 4) {
      return segments.slice(0, 4).join('/');
    }
    return url;
  }

  // Perforce: 保留到 depot 层级
  if (url.startsWith('ssl:') && url.includes('-//')) {
    const match = url.match(/^(ssl:[^:]+:\d+-\/\/[^/]+)/);
    return match ? match[1] : url;
  }

  // 其他 Git 仓库 (包括 GitLab, GitHub 等): 只保留域名
  const match = url.match(/^(https?:\/\/[^/]+)/);
  return match ? match[1] : url;
};

