const CODE_BACKTICKS = '```';
export const DEFAULT_TOPIC = '';
const ABORT_ERROR_NAME = 'AbortError';
export const REQUEST_TIMEOUT_NAME = 'RequestTimeout';

// 设置会话项目数量的最大阈值为 60。超过这个数量，系统会显示一个界面提示
// 以提醒用户会话太长可能会影响性能或用户体验。
