    if (attach) {
      set(() => ({ attachs: attach }));
    } else {
      set(() => ({ attachs: undefined }));
    }
  },

  update: (attach) => {
    set(() => ({ attachs: attach }));
  },
}));

function checkCodeBlockIsClose(content: string) {
  const flags = content.match(new RegExp(CODE_BACKTICKS, 'gm'));
  if (!flags) {
    return true;
  }
  return flags?.length % 2 === 0;
}

